UPDATE `sys_user` SET `name` = #{name},
pass_word = #{password},
per_code = #{percode}, depname = #{depname}, user_type = #{userType}, login_flag = #{loginflag}, menu_role = #{menurole}, modu_role = #{modurole}, butt_role = #{buttrole}, data_role = #{datarole}, update_user = #{createUser}, update_time = NOW(), remarks= #{remarks} WHERE id = #{id}

UPDATE `sys_user`
SET login_flag = #{loginflag},
    error_time = #{errorTime},
    error_count = #{errorCount}
WHERE id = #{id}

UPDATE `sys_user` SET
    login_ip = #{loginip},
    login_date = #{logindate}
WHERE id = #{id}
